(function(){

/* =========================
   TOKEN LOADER
========================= */
let DESIGN_TOKENS = null;

async function loadDesignTokens(){
  try{
    const res = await fetch('assets/data/design-tokens.json');
    const tokens = await res.json();
    DESIGN_TOKENS = tokens;
    applyTokenVars(tokens);
    applyTheme(getTheme());
    applyRoomEmotionTokens();
  }catch(e){
    console.warn('Token load failed', e);
  }
}

function applyTokenVars(tokens){
  const root = document.documentElement;

  function setVars(obj, prefix=[]){
    for(const key in obj){
      const val = obj[key];
      if(val && typeof val === 'object' && 'value' in val && typeof val.value !== 'object'){
        const name = '--' + [...prefix, key].join('-');
        root.style.setProperty(name, val.value);
      }else if(val && typeof val === 'object'){
        setVars(val, [...prefix, key]);
      }
    }
  }

  setVars(tokens);
}

function applyThemeTokenVars(themeName){
  if(!DESIGN_TOKENS || !DESIGN_TOKENS.themes || !DESIGN_TOKENS.themes[themeName]) return;
  const theme = DESIGN_TOKENS.themes[themeName];
  const root = document.documentElement;
  for(const key in theme){
    const entry = theme[key];
    if(key === 'extends' || key === 'value') continue;
    if(entry && typeof entry === 'object' && 'value' in entry){
      const varName = '--' + key.replace(/\./g, '-');
      root.style.setProperty(varName, entry.value);
    }
  }
}

function applyRoomEmotionTokens(){
  if(!DESIGN_TOKENS || !DESIGN_TOKENS.rooms) return;
  document.querySelectorAll('[data-emotion]').forEach(node => {
    const emotion = node.dataset.emotion;
    const roomSet = DESIGN_TOKENS.rooms[emotion];
    if(!roomSet) return;
    for(const key in roomSet){
      const entry = roomSet[key];
      if(entry && typeof entry === 'object' && 'value' in entry){
        node.style.setProperty('--room-' + key, entry.value);
      }
    }
  });
}


  const THEME_KEY = 'olivia-theme';
  function getTheme(){
    return localStorage.getItem(THEME_KEY) || 'luxury';
  }
  function applyTheme(theme){
    document.documentElement.setAttribute('data-theme', theme);
    applyThemeTokenVars(theme);
    applyRoomEmotionTokens();
    try { localStorage.setItem(THEME_KEY, theme); } catch(e) {}
  }
  const STORAGE_KEY = 'olivia-lang';
  const DEFAULT_LANG = 'zh-Hant';

  function getLang(){ return localStorage.getItem(STORAGE_KEY) || DEFAULT_LANG; }
  function setLang(lang){ localStorage.setItem(STORAGE_KEY, lang); applyI18n(lang); }

  function applyI18n(lang){
    const dict = window.OLIVIA_I18N[lang] || window.OLIVIA_I18N[DEFAULT_LANG];
    document.documentElement.lang = lang;
    document.querySelectorAll('[data-i18n]').forEach(node => {
      const key = node.dataset.i18n;
      if (dict[key]) node.textContent = dict[key];
    });
    document.querySelectorAll('[data-i18n-meta]').forEach(node => {
      const key = node.dataset.i18nMeta;
      if (dict[key]) node.setAttribute('content', dict[key]);
    });
    document.querySelectorAll('[data-i18n-attr]').forEach(node => {
      const specs = node.dataset.i18nAttr.split('|').map(s => s.trim()).filter(Boolean);
      specs.forEach(spec => {
        const parts = spec.split(':');
        const attr = parts.shift();
        const key = parts.join(':');
        if (attr && key && dict[key] != null) node.setAttribute(attr, dict[key]);
      });
    });
    const titleKeyHolder = document.querySelector('[data-i18n-title]');
    if (titleKeyHolder){
      const key = titleKeyHolder.dataset.i18nTitle;
      if (dict[key]) document.title = dict[key];
    }
    document.querySelectorAll('.lang-btn').forEach(btn => btn.classList.toggle('active', btn.dataset.lang === lang));
    if (typeof applyExtraI18n === 'function') applyExtraI18n(lang); if (typeof applySeoI18n === 'function') applySeoI18n(lang);
    if (typeof applyAuditLevelI18n === 'function') applyAuditLevelI18n(lang);
  }

  function initCarousels(){
    document.querySelectorAll('[data-carousel]').forEach((carousel, index) => {
      const track = carousel.querySelector('.carousel-track');
      const slides = [...carousel.querySelectorAll('.carousel-slide')];
      const dots = [...carousel.querySelectorAll('.carousel-dots span')];
      if (!track || slides.length < 2) return;
      let current = 0;
      const interval = Number(carousel.dataset.interval || 3800) + index * 120;
      const update = () => {
        track.style.transform = `translateX(-${current * 100}%)`;
        dots.forEach((dot, i) => dot.classList.toggle('active', i === current));
      };
      let timer = window.setInterval(() => { current = (current + 1) % slides.length; update(); }, interval);
      carousel.addEventListener('mouseenter', () => clearInterval(timer));
      carousel.addEventListener('mouseleave', () => {
        clearInterval(timer);
        timer = window.setInterval(() => { current = (current + 1) % slides.length; update(); }, interval);
      });
      let touchStartX = 0;
      let touchStartY = 0;
      track.addEventListener('touchstart', (event) => {
        if (!event.touches || !event.touches.length) return;
        touchStartX = event.touches[0].clientX;
        touchStartY = event.touches[0].clientY;
      }, { passive: true });
      track.addEventListener('touchend', (event) => {
        if (!event.changedTouches || !event.changedTouches.length) return;
        const dx = event.changedTouches[0].clientX - touchStartX;
        const dy = event.changedTouches[0].clientY - touchStartY;
        if (Math.abs(dx) < 48 || Math.abs(dx) < Math.abs(dy)) return;
        clearInterval(timer);
        current = dx < 0 ? (current + 1) % slides.length : (current - 1 + slides.length) % slides.length;
        update();
        timer = window.setInterval(() => { current = (current + 1) % slides.length; update(); }, interval);
      }, { passive: true });
      update();
    });
  }

  function initReveal(){
    const observer = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) entry.target.classList.add('is-visible');
      });
    }, { threshold:.18 });
    document.querySelectorAll('.reveal').forEach(el => observer.observe(el));
  }

  function initParallax(){
    const items = document.querySelectorAll('.parallax');
    if (!items.length) return;
    const onScroll = () => {
      const y = window.scrollY;
      items.forEach(el => {
        const speed = Number(el.dataset.speed || 0.08);
        el.style.setProperty('--parallax', `${Math.round(y * speed)}px`);
      });
    };
    onScroll();
    window.addEventListener('scroll', onScroll, { passive:true });
  }


  function initEditorialGalleries(){
    document.querySelectorAll('[data-editorial-gallery]').forEach(gallery => {
      const slides = [...gallery.querySelectorAll('.editorial-slide')];
      const thumbs = [...gallery.querySelectorAll('.editorial-thumb')];
      const dots = [...gallery.querySelectorAll('.editorial-dot')];
      const prev = gallery.querySelector('.editorial-arrow.prev');
      const next = gallery.querySelector('.editorial-arrow.next');
      if (!slides.length) return;
      let current = 0;
      let timer = null;

      const show = (index) => {
        current = (index + slides.length) % slides.length;
        slides.forEach((slide, i) => slide.classList.toggle('is-active', i === current));
        thumbs.forEach((thumb, i) => thumb.classList.toggle('is-active', i === current));
        dots.forEach((dot, i) => dot.classList.toggle('is-active', i === current));
      };

      const autoplay = () => {
        stop();
        if (slides.length < 2) return;
        timer = window.setInterval(() => show(current + 1), 4200);
      };
      const stop = () => { if (timer) clearInterval(timer); };

      thumbs.forEach((thumb, i) => thumb.addEventListener('click', () => { show(i); autoplay(); }));
      dots.forEach((dot, i) => dot.addEventListener('click', () => { show(i); autoplay(); }));
      if (prev) prev.addEventListener('click', () => { show(current - 1); autoplay(); });
      if (next) next.addEventListener('click', () => { show(current + 1); autoplay(); });

      gallery.addEventListener('mouseenter', stop);
      gallery.addEventListener('mouseleave', autoplay);
      show(0);
      autoplay();
    });
  }


  function initEmotionalHover(){
    const items = document.querySelectorAll('[data-depth]');
    items.forEach(item => {
      item.addEventListener('mousemove', (e) => {
        const rect = item.getBoundingClientRect();
        const x = (e.clientX - rect.left) / rect.width - 0.5;
        const y = (e.clientY - rect.top) / rect.height - 0.5;
        const depth = Number(item.dataset.depth || 12);
        item.style.transform = `rotateX(${(-y * depth).toFixed(2)}deg) rotateY(${(x * depth).toFixed(2)}deg) translateY(-4px)`;
      });
      item.addEventListener('mouseleave', () => {
        item.style.transform = '';
      });
    });
  }




  
function initTrueRandomDrift(){
    const cloud = document.querySelector('.random-drift-cloud');
    if(!cloud) return;
    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if(prefersReduced) return;

    const items = [...cloud.querySelectorAll('.museum-object')];
    if(!items.length) return;

    const cloudRect = () => cloud.getBoundingClientRect();
    const pad = 10;

    const states = items.map((el, i) => {
      const w = el.offsetWidth || 120;
      const h = el.offsetHeight || 90;
      return {
        el, w, h,
        x: 0, y: 0, r: 0,
        tx: 0, ty: 0, tr: 0,
        vx: 0, vy: 0,
        speed: 0.018 + Math.random() * 0.012,
        hover: false
      };
    });

    function overlaps(a, b, extra = 18){
      return !(
        a.x + a.w + extra < b.x ||
        a.x > b.x + b.w + extra ||
        a.y + a.h + extra < b.y ||
        a.y > b.y + b.h + extra
      );
    }

    function randomPos(s){
      const rect = cloudRect();
      const maxX = Math.max(pad, rect.width - s.w - pad);
      const maxY = Math.max(pad, rect.height - s.h - pad);
      return {
        x: pad + Math.random() * (maxX - pad),
        y: pad + Math.random() * (maxY - pad)
      };
    }

    function assignNonOverlappingTargets(){
      states.forEach((s, idx) => {
        let placed = false;
        for(let attempt = 0; attempt < 200 && !placed; attempt++){
          const pos = randomPos(s);
          const candidate = {x: pos.x, y: pos.y, w: s.w, h: s.h};
          const collide = states.some((o, j) => j !== idx && Math.abs(o.tx - candidate.x) < 0.01 ? overlaps(candidate, {x:o.tx, y:o.ty, w:o.w, h:o.h}) : overlaps(candidate, {x:o.tx, y:o.ty, w:o.w, h:o.h}));
          if(!collide){
            s.tx = pos.x;
            s.ty = pos.y;
            s.tr = (Math.random() * 8) - 4;
            placed = true;
          }
        }
        if(!placed){
          const pos = randomPos(s);
          s.tx = pos.x;
          s.ty = pos.y;
          s.tr = (Math.random() * 8) - 4;
        }
      });
    }

    // initial placement
    states.forEach((s, idx) => {
      let pos = {x: pad + idx * 12, y: pad + idx * 8};
      for(let attempt = 0; attempt < 200; attempt++){
        pos = randomPos(s);
        const candidate = {x: pos.x, y: pos.y, w: s.w, h: s.h};
        const collide = states.slice(0, idx).some(o => overlaps(candidate, o, 24));
        if(!collide) break;
      }
      s.x = s.tx = pos.x;
      s.y = s.ty = pos.y;
      s.r = s.tr = (Math.random() * 8) - 4;
      s.el.style.left = '0px';
      s.el.style.top = '0px';
    });

    assignNonOverlappingTargets();

    states.forEach((s) => {
      s.el.addEventListener('mouseenter', () => {
        s.hover = true;
      });
      s.el.addEventListener('mouseleave', () => {
        s.hover = false;
      });
    });

    let lastRetarget = performance.now();
    let raf = null;

    const tick = (t) => {
      const rect = cloudRect();

      if(t - lastRetarget > 3200){
        assignNonOverlappingTargets();
        lastRetarget = t;
      }

      // soft avoidance / separation
      for(let i = 0; i < states.length; i++){
        const a = states[i];
        if(a.hover) continue;

        // pull toward target
        a.vx += (a.tx - a.x) * 0.0018;
        a.vy += (a.ty - a.y) * 0.0018;

        for(let j = 0; j < states.length; j++){
          if(i === j) continue;
          const b = states[j];
          const dx = a.x - b.x;
          const dy = a.y - b.y;
          const dist = Math.hypot(dx, dy) || 1;
          const minDist = Math.max(a.w, b.w) * 0.72;
          if(dist < minDist){
            const force = (minDist - dist) * 0.0045;
            a.vx += (dx / dist) * force;
            a.vy += (dy / dist) * force;
          }
        }

        a.vx *= 0.965;
        a.vy *= 0.965;

        a.x += a.vx;
        a.y += a.vy;
        a.r += (a.tr - a.r) * 0.02;

        // contain
        a.x = Math.max(pad, Math.min(a.x, rect.width - a.w - pad));
        a.y = Math.max(pad, Math.min(a.y, rect.height - a.h - pad));

        a.el.style.transform = `translate3d(${a.x.toFixed(2)}px, ${a.y.toFixed(2)}px, 0) rotate(${a.r.toFixed(2)}deg)`;
      }

      raf = requestAnimationFrame(tick);
    };

    raf = requestAnimationFrame(tick);

    window.addEventListener('resize', () => {
      states.forEach(s => {
        s.w = s.el.offsetWidth || s.w;
        s.h = s.el.offsetHeight || s.h;
      });
      assignNonOverlappingTargets();
    });

    window.addEventListener('pagehide', () => {
      if (raf) cancelAnimationFrame(raf);
    }, { once:true });
  }

  function initMuseumMode(){
    const cloud = document.querySelector('.museum-cloud');
    if(!cloud) return;
    cloud.dataset.spotlight = 'on';
    const objects = [...cloud.querySelectorAll('.museum-object')];
    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if(prefersReduced) return;

    const resetObject = (obj) => {
      obj.style.transform = '';
      const label = obj.querySelector('.object-label');
      const core = obj.querySelector('.art-core');
      if(label) label.style.transform = 'translateZ(18px)';
      if(core) core.style.transform = 'translateZ(8px)';
    };

    objects.forEach(obj => {
      obj.addEventListener('mousemove', (e) => {
        const rect = obj.getBoundingClientRect();
        const x = (e.clientX - rect.left) / rect.width - 0.5;
        const y = (e.clientY - rect.top) / rect.height - 0.5;
        const rotateY = x * 12;
        const rotateX = -y * 10;
        obj.style.transform = `translateY(-8px) rotateX(${rotateX.toFixed(2)}deg) rotateY(${rotateY.toFixed(2)}deg) scale(1.03)`;
        const label = obj.querySelector('.object-label');
        const core = obj.querySelector('.art-core');
        if(label){
          label.style.transform = `translateZ(28px) translateX(${(x*6).toFixed(2)}px) translateY(${(y*6).toFixed(2)}px)`;
        }
        if(core){
          core.style.transform = `translateZ(16px) translateX(${(-x*4).toFixed(2)}px) translateY(${(-y*4).toFixed(2)}px)`;
        }
      });
      obj.addEventListener('mouseleave', () => resetObject(obj));
    });

    cloud.addEventListener('mousemove', (e) => {
      const rect = cloud.getBoundingClientRect();
      const x = ((e.clientX - rect.left) / rect.width) * 100;
      const y = ((e.clientY - rect.top) / rect.height) * 100;
      cloud.style.background = `
        radial-gradient(circle at ${x}% ${y}%, rgba(255,255,255,.24), transparent 18%),
        radial-gradient(circle at 15% 20%, rgba(255,255,255,.18), transparent 18%),
        radial-gradient(circle at 80% 18%, rgba(255,255,255,.10), transparent 16%),
        radial-gradient(circle at 50% 70%, rgba(242,213,199,.14), transparent 26%),
        linear-gradient(180deg, rgba(255,250,246,.28), rgba(255,250,246,.16))
      `;
    });
  }

  function initCinematicPanels(){
    const panels = document.querySelectorAll('.cinematic-panel');
    if(!panels.length) return;
    const observer = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if(entry.isIntersecting){
          entry.target.classList.add('is-visible');
        }
      });
    }, { threshold: 0.22 });
    panels.forEach(panel => observer.observe(panel));
  }

  function enhanceRoomLinks(){
    const page = document.querySelector('.editorial-page');
    if (!page) return;
    document.querySelectorAll('a[href^="#room-"]').forEach(link => {
      link.addEventListener('click', evt => {
        const id = link.getAttribute('href');
        const target = id ? document.querySelector(id) : null;
        if (!target) return;
        evt.preventDefault();
        target.scrollIntoView({ behavior:'smooth', block:'start' });
      });
    });
  }

  document.addEventListener('DOMContentLoaded', () => {
    applyTheme(getTheme());
    applyI18n(getLang());
    document.querySelectorAll('.lang-btn').forEach(btn => btn.addEventListener('click', () => setLang(btn.dataset.lang)));
    initCarousels();
    initReveal();
    initParallax();
    initEditorialGalleries();
    enhanceRoomLinks();
    initCinematicPanels();
    initMuseumMode();
    initTrueRandomDrift();
    initEmotionalHover();
  });
})();


