function applyExtraI18n(lang){
  const dict = window.OLIVIA_I18N[lang] || window.OLIVIA_I18N["en"];
  const path = (location.pathname.split('/').pop() || 'index.html');

  const setText = (selector, key, all=false) => {
    const nodes = all ? document.querySelectorAll(selector) : [document.querySelector(selector)];
    nodes.forEach((node) => { if(node && dict[key] != null) node.textContent = dict[key]; });
  };

  if(path === 'index.html' || path === ''){
    setText('.gallery-band .carousel-card:nth-child(1) .carousel-kicker', 'home.carousel1.kicker');
    setText('.gallery-band .carousel-card:nth-child(1) .carousel-title', 'home.carousel1.title');
    setText('.gallery-band .carousel-card:nth-child(2) .carousel-kicker', 'home.carousel2.kicker');
    setText('.gallery-band .carousel-card:nth-child(2) .carousel-title', 'home.carousel2.title');
    setText('.gallery-band .carousel-card:nth-child(3) .carousel-kicker', 'home.carousel3.kicker');
    setText('.gallery-band .carousel-card:nth-child(3) .carousel-title', 'home.carousel3.title');
  }

  if(path === 'cuisine.html'){
    setText('.quote-card .quote-meta', 'cuisine.quoteMeta');
    setText('.cuisine-gallery .carousel-card.tall .carousel-kicker', 'cuisine.gallery1.kicker');
    setText('.cuisine-gallery .carousel-card.tall .carousel-title', 'cuisine.gallery1.title');
    setText('.stack-grid .carousel-card:nth-child(1) .carousel-kicker', 'cuisine.gallery2.kicker');
    setText('.stack-grid .carousel-card:nth-child(1) .carousel-title', 'cuisine.gallery2.title');
    setText('.stack-grid .carousel-card:nth-child(2) .carousel-kicker', 'cuisine.gallery3.kicker');
    setText('.stack-grid .carousel-card:nth-child(2) .carousel-title', 'cuisine.gallery3.title');
  }

  if(path === 'contact.html'){
    setText('.brand-name', 'contact.contactTitle2');
    setText('.contact-card .subtle', 'contact.contactBody2');
    setText('.contact-hero .carousel-kicker', 'contact.galleryKicker');
    setText('.contact-hero .carousel-title', 'contact.galleryTitle');
    setText('.section.soft .section-title', 'contact.arrivalTitle');
  }

  if(path === 'room.html'){
    setText('.cinematic-hero .section-label', 'stories.heroLabel');
    setText('.cinematic-hero h1', 'stories.heroTitle');
    setText('.cinematic-hero .hero-deck', 'stories.heroBody');
    setText('.cinematic-split .story-kicker', 'stories.originLabel');
    setText('.cinematic-split h2', 'stories.originTitle');
    setText('.cinematic-split .story-body:nth-of-type(1)', 'stories.originBody1');
    setText('.cinematic-split .story-body:nth-of-type(2)', 'stories.originBody2');
    setText('.cinematic-centered .story-kicker', 'stories.philosophyLabel');
    setText('.cinematic-centered h2', 'stories.philosophyTitle');
    setText('.cinematic-centered .story-body:nth-of-type(1)', 'stories.philosophyBody1');
    setText('.cinematic-centered .story-body:nth-of-type(2)', 'stories.philosophyBody2');
    setText('.cinematic-band .story-kicker', 'stories.lifeLabel');
    setText('.cinematic-band h2', 'stories.lifeTitle');
    setText('.cinematic-band .story-body:nth-of-type(1)', 'stories.lifeBody1');
    setText('.cinematic-band .story-body:nth-of-type(2)', 'stories.lifeBody2');
    setText('.cinematic-mosaic .story-kicker', 'stories.livingLabel');
    setText('.cinematic-mosaic h2', 'stories.livingTitle');
    setText('.cinematic-mosaic .story-body', 'stories.livingBody');
    setText('.cinematic-close .story-kicker', 'stories.arrivalLabel');
    setText('.cinematic-close h2', 'stories.arrivalTitle');
    setText('.cinematic-close .story-body', 'stories.arrivalBody');
    setText('.cinematic-close .story-link', 'stories.arrivalCta');

    const objectKeys = ['joy','desire','adore','secret','love','plato','truth','affair','courage','eternity'];
    document.querySelectorAll('.object-cloud .object-label').forEach((node, i) => {
      const key = objectKeys[i];
      if(key && dict['stories.object.' + key] != null) node.textContent = dict['stories.object.' + key];
    });
  }

  if(path === 'rooms.html'){
    setText('.rooms-hero-copy .section-label', 'rooms.heroLabel2');
    setText('.rooms-hero-copy h1', 'rooms.heroTitle2');
    setText('.rooms-hero-copy .hero-deck', 'rooms.heroBody2');
    setText('.rooms-hero-aside .aside-label', 'rooms.notesLabel');
    setText('.rooms-hero-aside p:last-child', 'rooms.notesBody');

    const defs = [
      ['joy',['glow','breath','morning']],
      ['desire',['warmth','shadow','nearness']],
      ['adore',['tenderness','softness','grace']],
      ['secret',['shadow','privacy','silence']],
      ['love',['calm','warmth','closeness']],
      ['plato',['order','measure','stillness']],
      ['truth',['clarity','material','presence']],
      ['affair',['drama','allure','midnight']],
      ['courage',['grounded','poise','strength']],
      ['eternity',['air','stillness','timeless']]
    ];
    defs.forEach(([slug,tags]) => {
      const block = document.querySelector('#room-' + slug);
      if(!block) return;
      const kicker = block.querySelector('.story-kicker');
      const title = block.querySelector('h2');
      const quote = block.querySelector('.story-quote');
      const body = block.querySelector('.story-body');
      const figcap = block.querySelector('figcaption');
      if(kicker) kicker.textContent = dict['room.'+slug+'.label'] || dict['room.'+slug+'.zh'] || kicker.textContent;
      if(title) title.textContent = dict['room.'+slug+'.heading'] || dict['room.'+slug+'.en'] || title.textContent;
      if(quote) quote.textContent = dict['room.'+slug+'.quote'] || quote.textContent;
      if(body) body.textContent = dict['room.'+slug+'.body'] || body.textContent;
      if(figcap){
        const en = dict['room.'+slug+'.en'] || '';
        const zh = dict['room.'+slug+'.zh'] || '';
        figcap.textContent = lang === 'zh-Hant' ? `${zh} / ${en}` : `${en} / ${zh}`;
      }
      block.querySelectorAll('.room-sensory-tags span').forEach((tagNode, i) => {
        const tagKey = tags[i];
        if(tagKey && dict['rooms.tag.'+tagKey] != null) tagNode.textContent = dict['rooms.tag.'+tagKey];
      });
    });

    document.querySelectorAll('.collection-nav .experiential-pill').forEach((pill, i) => {
      const defs2 = ['joy','desire','adore','secret','love','plato','truth','affair','courage','eternity'];
      const slug = defs2[i];
      const sp = pill.querySelector('span');
      const em = pill.querySelector('em');
      if(sp && dict['room.'+slug+'.en']) sp.textContent = dict['room.'+slug+'.en'];
      if(em && dict['room.'+slug+'.zh']) em.textContent = dict['room.'+slug+'.zh'];
    });
  }
}


