function applySeoI18n(lang){
  const dict = window.OLIVIA_I18N[lang] || window.OLIVIA_I18N["en"];
  const page = (location.pathname.split('/').pop() || 'index.html');
  const map = {
    'index.html':['seo.index.title','seo.index.description'],
    'room.html':['seo.stories.title','seo.stories.description'],
    'rooms.html':['seo.rooms.title','seo.rooms.description'],
    'cuisine.html':['seo.cuisine.title','seo.cuisine.description'],
    'contact.html':['seo.contact.title','seo.contact.description']
  };
  const pair = map[page] || map['index.html'];
  const title = dict[pair[0]], desc = dict[pair[1]];
  if(title) document.title = title;
  if(desc){
    const meta = document.querySelector('meta[name="description"]');
    if(meta) meta.setAttribute('content', desc);
    document.querySelectorAll('meta[property="og:description"], meta[name="twitter:description"]').forEach(m => m.setAttribute('content', desc));
  }
  if(title){
    document.querySelectorAll('meta[property="og:title"], meta[name="twitter:title"]').forEach(m => m.setAttribute('content', title));
  }
}

