function initConversionSystem(){
  const guide = document.querySelector('.room-guide');
  const pills = document.querySelectorAll('.room-color-pill[data-room]');
  const copy = {
    "zh-Hant":{
      joy:"適合剛抵達，也適合重新開始",
      desire:"適合兩個人，或想更靠近自己的時刻",
      adore:"適合慢下來，被細節溫柔對待",
      secret:"適合不被打擾的片刻",
      love:"適合不需要理由的停留",
      plato:"適合思考，讓感受回到清楚",
      truth:"適合回到最純粹的自己",
      affair:"適合晚一點抵達，也適合不急著離開",
      courage:"適合整理自己，安靜而堅定",
      eternity:"適合停得更久，讓時間慢下來"
    },
    en:{
      joy:"For arrival, and for beginning again",
      desire:"For two, or for moving closer to yourself",
      adore:"For slowing down and feeling cared for",
      secret:"For a moment without interruption",
      love:"For a stay that needs no reason",
      plato:"For thought, clarity, and balance",
      truth:"For returning to the essential self",
      affair:"For late arrivals and unhurried nights",
      courage:"For quiet confidence",
      eternity:"For staying longer, where time slows down"
    }
  };
  const getLang = () => localStorage.getItem('olivia-lang') || document.documentElement.lang || 'zh-Hant';
  if(guide && pills.length){
    pills.forEach(pill => {
      pill.addEventListener('mouseenter', () => {
        const lang = getLang();
        const room = pill.dataset.room;
        guide.textContent = (copy[lang] && copy[lang][room]) || copy["zh-Hant"][room] || "";
        guide.classList.add('is-visible');
      });
      pill.addEventListener('mouseleave', () => {
        guide.classList.remove('is-visible');
      });
    });
  }
}


